json::Object
Asg2Json::operator()(CallExpr* obj)
{
  assert(obj->head);

  json::Object ret;
  Obj::Walked guard(obj);

  ret["kind"] = "CallExpr";

  json::Array inner;
  inner.push_back(self(obj->head));
  for (auto&& i : obj->args)
    inner.push_back(self(i));
  ret["inner"] = std::move(inner);

  return ret;
}

